let _ac = null;
function ac(){ if(!_ac)_ac=new(window.AudioContext||window.webkitAudioContext)(); return _ac; }

const bgMusic = new Audio('data:audio/mpeg;base64,');
bgMusic.loop = true; bgMusic.volume = 0.32;

function sndJump(){
  const a=ac(),o=a.createOscillator(),g=a.createGain();
  o.connect(g);g.connect(a.destination);o.type='square';
  o.frequency.setValueAtTime(200,a.currentTime);
  o.frequency.exponentialRampToValueAtTime(420,a.currentTime+0.1);
  g.gain.setValueAtTime(0.12,a.currentTime);
  g.gain.exponentialRampToValueAtTime(0.001,a.currentTime+0.14);
  o.start();o.stop(a.currentTime+0.14);
}
function sndDoubleJump(){
  const a=ac(),o=a.createOscillator(),g=a.createGain();
  o.connect(g);g.connect(a.destination);o.type='square';
  o.frequency.setValueAtTime(320,a.currentTime);
  o.frequency.exponentialRampToValueAtTime(640,a.currentTime+0.12);
  g.gain.setValueAtTime(0.1,a.currentTime);
  g.gain.exponentialRampToValueAtTime(0.001,a.currentTime+0.16);
  o.start();o.stop(a.currentTime+0.16);
}
function sndCoin(){
  const a=ac(),o=a.createOscillator(),g=a.createGain();
  o.connect(g);g.connect(a.destination);o.type='sine';
  o.frequency.setValueAtTime(900,a.currentTime);
  o.frequency.setValueAtTime(1320,a.currentTime+0.04);
  g.gain.setValueAtTime(0.18,a.currentTime);
  g.gain.exponentialRampToValueAtTime(0.001,a.currentTime+0.13);
  o.start();o.stop(a.currentTime+0.13);
}
function sndKill(){
  const a=ac();
  // noise burst
  const sz=Math.floor(a.sampleRate*0.22);
  const buf=a.createBuffer(1,sz,a.sampleRate);
  const d=buf.getChannelData(0);for(let i=0;i<sz;i++)d[i]=(Math.random()*2-1);
  const ns=a.createBufferSource();ns.buffer=buf;
  const flt=a.createBiquadFilter();flt.type='bandpass';
  flt.frequency.setValueAtTime(500,a.currentTime);
  flt.frequency.exponentialRampToValueAtTime(80,a.currentTime+0.22);
  flt.Q.value=1.2;
  const gn=a.createGain();gn.gain.setValueAtTime(0.5,a.currentTime);
  gn.gain.exponentialRampToValueAtTime(0.001,a.currentTime+0.22);
  ns.connect(flt);flt.connect(gn);gn.connect(a.destination);ns.start();ns.stop(a.currentTime+0.22);
  // pitch-drop synth
  const o=a.createOscillator(),g=a.createGain();
  o.connect(g);g.connect(a.destination);o.type='sawtooth';
  o.frequency.setValueAtTime(280,a.currentTime);
  o.frequency.exponentialRampToValueAtTime(55,a.currentTime+0.28);
  g.gain.setValueAtTime(0.22,a.currentTime);
  g.gain.exponentialRampToValueAtTime(0.001,a.currentTime+0.28);
  o.start();o.stop(a.currentTime+0.28);
}
function sndPowerup(){
  const a=ac();
  [330,440,550,660].forEach(function(fr,i){
    const o=a.createOscillator(),g=a.createGain();
    o.connect(g);g.connect(a.destination);o.type='square';o.frequency.value=fr;
    const t=a.currentTime+i*0.07;
    g.gain.setValueAtTime(0.14,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.14);
    o.start(t);o.stop(t+0.14);
  });
}
function sndHurt(){
  const a=ac(),o=a.createOscillator(),g=a.createGain();
  o.connect(g);g.connect(a.destination);o.type='sawtooth';
  o.frequency.setValueAtTime(180,a.currentTime);
  o.frequency.exponentialRampToValueAtTime(55,a.currentTime+0.32);
  g.gain.setValueAtTime(0.28,a.currentTime);
  g.gain.exponentialRampToValueAtTime(0.001,a.currentTime+0.32);
  o.start();o.stop(a.currentTime+0.32);
}
function sndDead(){
  const a=ac();
  [440,330,220,110].forEach(function(fr,i){
    const o=a.createOscillator(),g=a.createGain();
    o.connect(g);g.connect(a.destination);o.type='sawtooth';o.frequency.value=fr;
    const t=a.currentTime+i*0.13;
    g.gain.setValueAtTime(0.2,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.18);
    o.start(t);o.stop(t+0.18);
  });
}
function sndWin(){
  const a=ac();
  [330,440,550,660,880].forEach(function(fr,i){
    const o=a.createOscillator(),g=a.createGain();
    o.connect(g);g.connect(a.destination);o.type='square';o.frequency.value=fr;
    const t=a.currentTime+i*0.1;
    g.gain.setValueAtTime(0.16,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.28);
    o.start(t);o.stop(t+0.28);
  });
}
